<script>
function showError(msg){const b=document.getElementById('errorBanner');b.textContent=msg;b.classList.add('visible');setTimeout(()=>b.classList.remove('visible'),6000);}

let currentNoticeType = 'IT';
let answers = {};

const QUESTIONS = {
    IT: [
        {id: 'q1', text: 'Does the notice ask you to <strong>produce documents or information</strong> for an assessment year?'},
        {id: 'q2', text: 'Does the notice ask you to <strong>file a return</strong> that was not filed earlier?'},
        {id: 'q3', text: 'Does the notice mention <strong>"selected for scrutiny"</strong>, "e-assessment", or "compulsory selection"?'},
        {id: 'q4', text: 'Does the notice mention <strong>"income has escaped assessment"</strong> or "reason to believe"?'},
        {id: 'q5', text: 'Does the notice state a <strong>specific tax demand amount</strong> payable?'},
        {id: 'q6', text: 'Does the notice mention <strong>"penalty proceedings"</strong>, Section 271, or Section 270A?'},
        {id: 'q7', text: 'Is this a <strong>show-cause notice before reassessment</strong> (Section 148A(b)) with a 7-15 day window?'},
        {id: 'q8', text: 'Does the notice carry a <strong>valid DIN (20-digit code)</strong>?'}
    ],
    GST: [
        {id: 'q1', text: 'Is the notice in form <strong>ASMT-10</strong> or does it mention "scrutiny of returns"?'},
        {id: 'q2', text: 'Does the notice state a <strong>specific tax / penalty demand</strong> amount?'},
        {id: 'q3', text: 'Does the notice allege <strong>fraud, willful misstatement, or suppression</strong> of facts?'},
        {id: 'q4', text: 'Is the notice in form <strong>DRC-01A</strong> (pre-show-cause intimation)?'},
        {id: 'q5', text: 'Is the notice in form <strong>DRC-01</strong> with Section 73 or 74 citation?'},
        {id: 'q6', text: 'Is the notice a <strong>final order in form DRC-07</strong>?'},
        {id: 'q7', text: 'Does the notice cite <strong>Section 76</strong> (tax collected but not paid)?'},
        {id: 'q8', text: 'Does the notice carry a <strong>valid DIN (20-digit code)</strong>?'}
    ]
};

const STATE_CITY = {
    'Maharashtra': {city: 'pune', cityDisplay: 'Pune / Mumbai'},
    'Delhi': {city: 'delhi', cityDisplay: 'Delhi'},
    'Haryana': {city: 'gurugram', cityDisplay: 'Gurugram'},
    'Karnataka': {city: 'bangalore', cityDisplay: 'Bangalore'},
    'Tamil Nadu': {city: 'chennai', cityDisplay: 'Chennai'},
    'Telangana': {city: 'hyderabad', cityDisplay: 'Hyderabad'},
    'Andhra Pradesh': {city: 'hyderabad', cityDisplay: 'Hyderabad (nearest)'},
    'West Bengal': {city: 'kolkata', cityDisplay: 'Kolkata'},
    'Gujarat': {city: 'ahmedabad', cityDisplay: 'Ahmedabad'},
    'Uttar Pradesh': {city: 'noida', cityDisplay: 'Noida / Lucknow'},
    'Rajasthan': {city: 'jaipur', cityDisplay: 'Jaipur'},
    'Kerala': {city: 'kochi', cityDisplay: 'Kochi'},
    'Punjab': {city: 'chandigarh', cityDisplay: 'Chandigarh'},
    'Madhya Pradesh': {city: 'indore', cityDisplay: 'Indore / Bhopal'},
    'Other': {city: '', cityDisplay: 'Pan-India digital'}
};

function renderQuestions(){
    const container = document.getElementById('questionContainer');
    container.innerHTML = '';
    QUESTIONS[currentNoticeType].forEach((q, idx) => {
        const block = document.createElement('div');
        block.className = 'q-block';
        block.id = q.id + '-block';
        block.innerHTML = '<div class="q-text"><span class="q-num">Q' + (idx+1) + '</span>' + q.text + '</div>' +
            '<div class="q-options">' +
            '<button type="button" class="q-opt" data-q="' + q.id + '" data-val="yes" onclick="answerQ(this)">Yes</button>' +
            '<button type="button" class="q-opt" data-q="' + q.id + '" data-val="no" onclick="answerQ(this)">No</button>' +
            '<button type="button" class="q-opt" data-q="' + q.id + '" data-val="skip" onclick="answerQ(this)">Skip</button>' +
            '</div>';
        container.appendChild(block);
    });
}

function answerQ(b){
    const e = b.closest ? (b.closest('.q-opt') || b) : b;
    const qid = e.dataset.q;
    const val = e.dataset.val;
    answers[qid] = val;
    // Update visual state
    const block = document.getElementById(qid + '-block');
    block.querySelectorAll('.q-opt').forEach(x => x.classList.remove('active-yes','active-no','active-skip'));
    if(val === 'yes'){e.classList.add('active-yes'); block.classList.remove('answered-no'); block.classList.add('answered-yes');}
    else if(val === 'no'){e.classList.add('active-no'); block.classList.remove('answered-yes'); block.classList.add('answered-no');}
    else {e.classList.add('active-skip'); block.classList.remove('answered-yes','answered-no');}
}

function setNoticeType(b){
    const e = b.closest ? (b.closest('.toggle-btn') || b) : b;
    currentNoticeType = e.dataset.type;
    e.parentElement.querySelectorAll('.toggle-btn').forEach(x => x.classList.remove('active'));
    e.classList.add('active');
    answers = {};
    renderQuestions();
    document.getElementById('resultSection').classList.remove('visible');
}

function identifyIT(){
    if(answers.q7 === 'yes') return {section: 'Section 148A(b)', desc: 'Show-cause notice before reassessment (mandatory pre-condition for Section 148 since Finance Act 2021)', urgency: 'high', replyWindow: '7-15 days', replyDesc: 'Short window — respond immediately', tier: 'Premium', tierDesc: 'Full representation + 148A(d) order management', explain: 'Section 148A(b) is the show-cause notice that the Assessing Officer must issue BEFORE issuing a Section 148 reassessment notice (since Finance Act 2021). This is the taxpayer\'s chance to argue why income has not escaped assessment. A well-drafted response can prevent the Section 148 notice itself.', actions: ['Reply within the specified deadline (7-15 days, not negotiable)', 'Address each "reason to believe" cited by the AO', 'Provide supporting documents for the relevant assessment year', 'If AO passes adverse order under 148A(d), challenge in writ jurisdiction', 'Engage CA with Section 148A specialisation']};
    if(answers.q4 === 'yes') return {section: 'Section 148', desc: 'Reassessment notice — income allegedly escaped assessment', urgency: 'high', replyWindow: '30 days', replyDesc: 'File return for the relevant AY', tier: 'Premium', tierDesc: 'End-to-end reassessment representation', explain: 'Section 148 authorises reassessment of income that has allegedly escaped assessment in earlier years. The AO must follow Section 148A procedure first. The notice requires you to file a return for the relevant AY within 30 days.', actions: ['Verify whether Section 148A(b) was issued first — if not, the 148 notice may be defective', 'File the return as required (within 30 days)', 'Prepare full documentation for the relevant AY', 'Identify limitation period (4 / 6 / 10 years based on amount and category)', 'Engage CA immediately for response strategy']};
    if(answers.q3 === 'yes') return {section: 'Section 143(2)', desc: 'Scrutiny notice — return selected for detailed verification', urgency: 'high', replyWindow: '30 days', replyDesc: 'Plus follow-up hearings', tier: 'Premium', tierDesc: 'End-to-end scrutiny representation', explain: 'Section 143(2) scrutiny notice means your filed return has been selected for detailed verification. Must be served within 3 months from end of FY in which return was filed. Non-response triggers Section 144 best-judgment assessment.', actions: ['Reply on e-Proceedings tab within 30 days', 'Compile all supporting documents for income claimed', 'Reconcile any discrepancy with Form 26AS, AIS, TIS', 'Be prepared for multiple rounds of questions', 'Faceless assessment — prepare for video conference hearing']};
    if(answers.q5 === 'yes' && answers.q6 === 'yes') return {section: 'Section 271 / 270A', desc: 'Penalty proceedings notice with demand amount', urgency: 'high', replyWindow: '30 days', replyDesc: 'Mandatory response with grounds', tier: 'Premium', tierDesc: 'Penalty waiver application + appeal', explain: 'Penalty proceedings under Section 271 (older) or 270A (newer) for under-reporting / misreporting of income. Penalty ranges from 50% (under-reporting) to 200% (misreporting) of tax. Section 270AA gives waiver if tax + interest paid within specified time.', actions: ['Evaluate Section 270AA waiver eligibility (pay tax + interest)', 'Draft detailed reply addressing each ground of penalty', 'Cite favourable case law (e.g., Reliance Petroproducts, MAK Data)', 'Prepare for personal hearing under faceless penalty proceedings', 'Plan appeal to CIT(A) if penalty is confirmed']};
    if(answers.q5 === 'yes') return {section: 'Section 156', desc: 'Notice of demand — specific tax/penalty amount payable', urgency: 'high', replyWindow: '30 days to pay', replyDesc: 'Or appeal within 30 days', tier: 'Premium', tierDesc: 'Stay application + appeal management', explain: 'Section 156 is the formal demand notice following an assessment / reassessment order. You have 30 days to pay (or 30 days to appeal with stay application). Non-payment triggers Section 220 recovery procedures.', actions: ['Verify the demand calculation against the assessment order', 'File appeal to CIT(A) within 30 days if disputing', 'File stay application under Section 220(6) to stop recovery', 'Negotiate instalment plan if cash flow constrained', 'Plan payment + interest under Section 220(2)']};
    if(answers.q2 === 'yes') return {section: 'Section 142(1)(i)', desc: 'Notice to file return that was not filed earlier', urgency: 'medium', replyWindow: '15-30 days', replyDesc: 'As specified in notice', tier: 'Standard', tierDesc: 'Return filing + compliance', explain: 'Section 142(1)(i) is a notice to file return when the assessee has not filed return for an AY. Often issued to taxpayers identified via Form 26AS, AIS, or third-party reporting. Filing the return promptly avoids best-judgment assessment.', actions: ['File the return for the specified AY within deadline', 'Compute correct tax liability including any TDS already deducted', 'Pay self-assessment tax + interest under Section 234A/B/C', 'Maintain audit trail of all income and expenses', 'Engage CA for return filing especially if business income']};
    if(answers.q1 === 'yes') return {section: 'Section 142(1)', desc: 'Information notice — produce documents / explanation', urgency: 'medium', replyWindow: '15-30 days', replyDesc: 'As specified', tier: 'Standard', tierDesc: 'Response drafting + filing', explain: 'Section 142(1) is a preliminary information notice. The AO is asking for documents, accounts, or explanations before deciding whether to proceed with scrutiny. A thorough, well-organised response often avoids scrutiny escalation.', actions: ['List all documents requested in the notice', 'Reply on e-Proceedings tab with all annexures', 'Be precise — do not volunteer additional information', 'Keep contemporaneous notes of any reconciliation', 'Engage CA to draft a professional response']};
    if(answers.q5 === 'no' && answers.q8 === 'yes') return {section: 'Section 143(1)', desc: 'Intimation after CPC processing of return', urgency: 'low', replyWindow: '30 days (if disagreeing)', replyDesc: 'No reply needed if accepting', tier: 'Basic', tierDesc: 'Review + rectification if needed', explain: 'Section 143(1) intimation is an automated computation summary from CPC Bengaluru after processing your return. Most intimations show "Refund Issued" or "No Demand No Refund" — no action needed. If demand or rejection of refund, file rectification under Section 154 or appeal within 30 days.', actions: ['Verify CPC computation against your filed return', 'If matching — no action needed (accept the intimation)', 'If discrepancy — file rectification under Section 154 online', 'If disagreeing with rectification — file appeal to CIT(A)', 'Save the intimation as proof of return processing']};
    // Default fallback
    return {section: 'Section 142(1) (likely)', desc: 'Likely a preliminary information / scrutiny notice', urgency: 'medium', replyWindow: '15-30 days', replyDesc: 'Review notice carefully', tier: 'Standard', tierDesc: 'Recommend CA review for confirmation', explain: 'Based on the answers provided, the notice appears to be an Income Tax preliminary notice — most likely Section 142(1) for documents/information, possibly leading to Section 143(2) scrutiny. We recommend a CA review the actual notice document for confirmation.', actions: ['Forward the notice to a CA for review', 'Verify DIN and authenticity on incometax.gov.in', 'Note the reply deadline precisely', 'Begin compilation of relevant documents', 'Schedule the free 15-min review call']};
}

function identifyGST(){
    if(answers.q6 === 'yes') return {section: 'DRC-07 (Order)', desc: 'Final order of demand — appeal within 3 months', urgency: 'critical', replyWindow: '3 months for appeal', replyDesc: 'Recovery starts after 3 months', tier: 'Premium + Litigation', tierDesc: 'Appeal + pre-deposit + stay', explain: 'DRC-07 is the final adjudication order under Section 73/74. Appeal lies with First Appellate Authority within 3 months. 10% pre-deposit of disputed tax required for appeal. Recovery proceedings under Section 79 start after expiry of 3 months if no appeal filed.', actions: ['File appeal in FORM GST APL-01 within 3 months', 'Pay mandatory 10% pre-deposit of disputed tax', 'Compile complete grounds of appeal with case law', 'Apply for stay of recovery during appeal pendency', 'Engage CA + GST litigator immediately']};
    if(answers.q3 === 'yes' && answers.q5 === 'yes') return {section: 'Section 74 / DRC-01', desc: 'Demand notice alleging fraud / willful suppression (100% penalty)', urgency: 'high', replyWindow: '30 days', replyDesc: 'Mandatory detailed reply', tier: 'Premium', tierDesc: 'Re-categorisation challenge + reply', explain: 'Section 74 applies when the department alleges fraud, willful misstatement, or suppression. Penalty is 100% of tax. Many Section 74 notices can be challenged as wrongly categorised — re-classify to Section 73 (10% penalty) by demonstrating absence of fraudulent intent.', actions: ['Verify if DRC-01A pre-show-cause was issued first (mandatory)', 'Build defence that no fraud / suppression / willful misstatement existed', 'Cite case law on what constitutes fraud (specific intent test)', 'Pay tax + interest before order to reduce penalty to 25%', 'Engage GST litigation specialist']};
    if(answers.q5 === 'yes') return {section: 'Section 73 / DRC-01', desc: 'Demand notice — non-fraud (10% or ₹10K penalty)', urgency: 'high', replyWindow: '30 days', replyDesc: 'Reply with reconciliation', tier: 'Premium', tierDesc: 'Reply + documentation + hearing', explain: 'Section 73 demand for tax not paid / short paid / wrong ITC where no fraud is alleged. 3-year limitation from due date of annual return. Penalty capped at 10% of tax or ₹10,000 (whichever higher). Often arises from GSTR-3B vs 2B mismatch or supplier non-compliance.', actions: ['Reconcile the alleged demand against GSTR-3B / 2B / books', 'Provide supplier compliance evidence for ITC disputes', 'Pay disputed tax + interest before order to avoid penalty', 'File reply on GST portal with all reconciliations', 'Prepare for personal hearing']};
    if(answers.q7 === 'yes') return {section: 'Section 76 / DRC-01', desc: 'Tax collected but not paid — strict liability', urgency: 'high', replyWindow: '30 days', replyDesc: 'Recovery is mandatory', tier: 'Premium', tierDesc: 'Reconciliation + payment strategy', explain: 'Section 76 applies when a person collected GST from customers but did not deposit it with the government. No defence of "no fraud" — the tax must be paid with interest and penalty. Limitation does not apply.', actions: ['Verify the alleged collection vs deposit gap', 'Reconcile GSTR-1 (outward supply tax) vs GSTR-3B (tax paid)', 'Compute interest under Section 50 (18% p.a.)', 'Compute penalty under Section 76 (up to 100% of tax)', 'Pay immediately to limit penalty exposure']};
    if(answers.q4 === 'yes') return {section: 'DRC-01A (Pre-SCN)', desc: 'Pre-show-cause intimation — opportunity to pay before formal SCN', urgency: 'medium', replyWindow: '15 days', replyDesc: 'Pay or contest', tier: 'Standard', tierDesc: 'Reconciliation + strategic payment', explain: 'DRC-01A is the pre-show-cause intimation under Rule 142(1A). It gives the taxpayer 15 days to either accept and pay the disputed amount (avoiding penalty) or contest. Mandatory before any Section 74 SCN.', actions: ['Evaluate whether to pay (no penalty) or contest', 'Compute actual disputed tax + interest', 'If paying — file FORM DRC-03 with full reconciliation', 'If contesting — prepare grounds for DRC-01 response', 'Engage CA for strategic decision']};
    if(answers.q1 === 'yes') return {section: 'Section 61 / ASMT-10', desc: 'Scrutiny of returns — explain discrepancies', urgency: 'medium', replyWindow: '30 days', replyDesc: 'Reply with reconciliation', tier: 'Standard', tierDesc: 'Reply drafting + reconciliation', explain: 'ASMT-10 is a scrutiny notice under Section 61 asking for explanation of discrepancies in returns (GSTR-1 vs 3B vs 2B mismatch, ITC vs supplier, etc.). A thorough satisfactory response often prevents escalation to DRC-01 under Section 73 / 74.', actions: ['Reconcile each discrepancy item by item', 'Get supplier compliance evidence for ITC disputes', 'Reply on GST portal under "Reply to Scrutiny Notice"', 'Attach detailed reconciliation working as annexure', 'File rectifications via amendments if errors found']};
    if(answers.q5 === 'no' && answers.q2 === 'no' && answers.q8 === 'no') return {section: 'GSTR-3A (likely)', desc: 'Notice for non-filing of returns', urgency: 'high', replyWindow: '15 days', replyDesc: 'File returns immediately', tier: 'Standard', tierDesc: 'Return filing + late fee', explain: 'GSTR-3A is issued when GST returns (GSTR-1 or GSTR-3B) are not filed for one or more periods. Non-response can lead to cancellation of registration. File all pending returns with late fee and interest immediately.', actions: ['Identify all pending return periods', 'Compute late fee (₹50/day per return capped at ₹5,000)', 'Pay tax + interest + late fee', 'File all pending GSTR-1 and GSTR-3B', 'Update reply on portal once returns are filed']};
    // Default
    return {section: 'Section 73 (most likely) / ASMT-10', desc: 'Likely a GST demand or scrutiny notice', urgency: 'medium', replyWindow: '30 days', replyDesc: 'Review notice carefully', tier: 'Standard', tierDesc: 'CA review recommended', explain: 'Based on the answers, the notice is likely a GST scrutiny (ASMT-10) or a Section 73 demand. We recommend a CA review the actual document to confirm — the section determines the response strategy and penalty exposure.', actions: ['Forward the notice to a CA for review', 'Verify DIN authenticity on cbic.gov.in', 'Note the reply deadline precisely', 'Begin reconciliation of GSTR data', 'Schedule the free 15-min review call']};
}

function identify(){
    const state = document.getElementById('businessState').value;
    if(Object.keys(answers).length < 6){
        showError('Please answer at least 6 of the 8 questions for an accurate identification.');
        return;
    }
    const result = currentNoticeType === 'IT' ? identifyIT() : identifyGST();

    document.getElementById('resSection').textContent = result.section;
    document.getElementById('resSectionDesc').textContent = result.desc;

    const ub = document.getElementById('urgencyBanner');
    ub.classList.remove('high','medium','low','critical');
    const urgencyMap = {
        critical: {cls: 'high', icon: '🚨', label: 'CRITICAL URGENCY'},
        high: {cls: 'high', icon: '⚠', label: 'HIGH URGENCY'},
        medium: {cls: 'medium', icon: '⚡', label: 'MEDIUM URGENCY'},
        low: {cls: 'low', icon: '✓', label: 'LOW URGENCY'}
    };
    const u = urgencyMap[result.urgency];
    ub.classList.add(u.cls === 'high' && result.urgency === 'critical' ? 'high' : u.cls);
    document.getElementById('urgencyIcon').textContent = u.icon;
    document.getElementById('urgencyMeta').innerHTML = '<strong>' + u.label + '</strong> — ' + (result.urgency === 'critical' ? 'Immediate action required. Engage a CA TODAY.' : result.urgency === 'high' ? 'Respond promptly. Engage a CA within the next 48 hours.' : result.urgency === 'medium' ? 'Prepare a thorough response within the deadline.' : 'Routine — review and file rectification only if disagreeing.');

    document.getElementById('resReplyWindow').textContent = result.replyWindow;
    document.getElementById('resReplyDesc').textContent = result.replyDesc;
    document.getElementById('resTier').textContent = result.tier;
    document.getElementById('resTierDesc').textContent = result.tierDesc;
    document.getElementById('sectionExplain').innerHTML = result.explain;

    const ul = document.getElementById('actionItems');
    ul.innerHTML = '';
    result.actions.forEach(a => {
        const li = document.createElement('li');
        li.textContent = a;
        ul.appendChild(li);
    });

    // CTA — route to city page
    const cityInfo = STATE_CITY[state] || STATE_CITY['Other'];
    const cta = document.getElementById('cityCta');
    if(cityInfo.city){
        // For IT notices route to IT city page; for GST route to general /gst-notice-reply
        if(currentNoticeType === 'IT'){
            cta.href = '/income-tax-notice/' + cityInfo.city;
            document.getElementById('cityCtaText').textContent = 'IT Notice CA in ' + cityInfo.cityDisplay;
        } else {
            cta.href = '/gst-notice-reply';
            document.getElementById('cityCtaText').textContent = 'GST Notice Reply Service';
        }
    } else {
        cta.href = currentNoticeType === 'IT' ? '/income-tax-notice-response' : '/gst-notice-reply';
        document.getElementById('cityCtaText').textContent = currentNoticeType === 'IT' ? 'IT Notice Response' : 'GST Notice Reply';
    }

    document.getElementById('ctaHead').textContent = result.urgency === 'critical' || result.urgency === 'high' ? 'Urgent: Get CA help today for this ' + result.section + ' notice' : 'Need help responding to this ' + result.section + ' notice?';

    const section = document.getElementById('resultSection');
    section.classList.add('visible');
    requestAnimationFrame(function(){requestAnimationFrame(function(){section.scrollIntoView({behavior:'smooth',block:'start'});});});
}

function resetCalc(){
    answers = {};
    document.querySelectorAll('.toggle-group').forEach(g => {g.querySelectorAll('.toggle-btn').forEach(x => x.classList.remove('active'));});
    document.querySelector('.toggle-btn[data-type="IT"]').classList.add('active');
    currentNoticeType = 'IT';
    document.getElementById('businessState').value = 'Maharashtra';
    renderQuestions();
    document.getElementById('resultSection').classList.remove('visible');
    document.getElementById('errorBanner').classList.remove('visible');
}

function toggleFaq(e){const b=e.closest?(e.closest('.faq-question')||e):e;const it=b.closest('.faq-item');if(!it)return;const o=it.classList.contains('open');document.querySelectorAll('.faq-item').forEach(i=>{i.classList.remove('open');const q=i.querySelector('.faq-question');if(q)q.setAttribute('aria-expanded','false');});if(!o){it.classList.add('open');b.setAttribute('aria-expanded','true');}}

renderQuestions();

const navLinks=document.querySelectorAll('.toc-nav a');
window.addEventListener('scroll',()=>{const s=document.querySelectorAll('section[id], header[id]');let c='';s.forEach(x=>{const t=x.offsetTop-100;if(window.pageYOffset>=t)c=x.getAttribute('id');});navLinks.forEach(l=>{l.classList.toggle('active',l.getAttribute('href')==='#'+c);});});
</script>


